import { useEffect, useState } from "react";
import Navbar from "./components/Navbar";
import Hero from "./components/Hero";
import About from "./components/About";
import Skills from "./components/Skills";
import Projects from "./components/Projects";
import "./App.css";

const sectionIds = [
  "home",
  "about",
  "skills",
  "projects",
  "experience",
  "contact",
];

export default function App() {
  const [activeSection, setActiveSection] = useState("home");

  useEffect(() => {
    const options = {
      root: null,
      rootMargin: "-20% 0px -55% 0px",
      threshold: 0.1,
    };

    const handleIntersect = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersect, options);
    sectionIds.forEach((id) => {
      const el = document.getElementById(id);
      if (el) {
        observer.observe(el);
      }
    });

    return () => {
      observer.disconnect();
    };
  }, []);

  useEffect(() => {
    const revealItems = document.querySelectorAll(".scroll-reveal");
    const revealObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("in-view");
            revealObserver.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15 }
    );

    revealItems.forEach((item) => revealObserver.observe(item));
    return () => revealObserver.disconnect();
  }, []);

  return (
    <div className="app-root">
      <Navbar activeSection={activeSection} />

      <main>
        <Hero />

        <About />

        <Skills />

        <Projects />

        <section id="experience" className="section section-placeholder scroll-reveal">
          <div className="container">
            <h2 className="section-title">Experience</h2>
            <p className="section-text">
              Share your professional timeline or highlights here.
            </p>
          </div>
        </section>

        <section id="contact" className="section section-placeholder scroll-reveal">
          <div className="container">
            <h2 className="section-title">Contact</h2>
            <p className="section-text">
              Add your email, socials, or a contact form here.
            </p>
          </div>
        </section>
      </main>
    </div>
  );
}
